// === KEYBOARD EVENTS ===
document.addEventListener('keydown', (e) => {
    console.log('Tombol ditekan:', e.key);  // "a", "Enter", "Escape", dll.
    console.log('Kode:', e.code);           // "KeyA", "Enter", "Escape"

